const videos = [];
const inputItem = $input.first().json;
const limit = $('Set Niche').first().json.limit; 

if (!inputItem || !inputItem.data || !inputItem.data.markdown) {
    return [{ json: { error: "Data Not Found." } }];
}

const markdown = inputItem.data.markdown;

const cleanString = (str) => {
    return str.replace(/\\/g, '').trim();
};

const parseNumericValue = (value) => {
    if (!value || value === 'N/A') return 0;
    const cleanedValue = value.toLowerCase().replace(/ subscribers| views/g, '').trim();
    const multiplier = cleanedValue.slice(-1);
    let num = parseFloat(cleanedValue);
    if (isNaN(num)) return 0;

    if (multiplier === 'k') {
        num *= 1000;
    } else if (multiplier === 'm') {
        num *= 1000000;
    } else if (multiplier === 'b') {
        num *= 1+1234567890;
    }

    return num;
};

const parseTimeAgo = (timeStr) => {
    if (!timeStr || timeStr === 'N/A') return 999999;

    const lowerTime = timeStr.toLowerCase();
    const match = lowerTime.match(/(\d+)\s*(second|minute|hour|day|week|month|year)/);

    if (!match) return 999999;

    const value = parseInt(match[1]);
    const unit = match[2];

    switch(unit) {
        case 'second': return value / 86400;
        case 'minute': return value / 1440;
        case 'hour': return value / 24;
        case 'day': return value;
        case 'week': return value * 7;
        case 'month': return value * 30;
        case 'year': return value * 365;
        default: return 999999;
    }
};

const subscriberData = {};
const channelSubscriberRegex = /@([^•]+?)•(\d+\.?\d*[KMB]? subscribers)/g;
let subMatch;
while ((subMatch = channelSubscriberRegex.exec(markdown)) !== null) {
    subscriberData[subMatch[1].trim()] = subMatch[2].trim();
}

const videoBlockRegex = new RegExp(
    /### \[(.*?)\]\((https:\/\/www\.youtube\.com\/watch\?v=[^&]+).*?\)/.source +
    /[\s\S]*?\[(.*?)\]\((https:\/\/www\.youtube\.com\/@([^)]+))\)/.source +
    /[\s\S]*?(\d+\.?\d*[KMB]? views)(.*?)ago/.source,
    'g'
);

const matches = [...markdown.matchAll(videoBlockRegex)];

for (const match of matches) {
    const title = cleanString(match[1]);
    const url = cleanString(match[2]);
    const channelName = cleanString(match[3]);
    const channelHandle = cleanString(match[5]); 
    const viewsRaw = cleanString(match[6]);
    const timeAgo = cleanString(match[7] + 'ago');

    const channelSubscriberRaw = subscriberData[channelHandle] || 'N/A';

    const viewsNumeric = parseNumericValue(viewsRaw);
    const subscriberNumeric = parseNumericValue(channelSubscriberRaw);
    const daysAgo = parseTimeAgo(timeAgo);

    videos.push({
        title: title,
        url: url,
        channelName: channelName,
        channelHandle: `@${channelHandle}`,
        channelSubscriber: channelSubscriberRaw,
        views: viewsRaw,
        uploadedAgo: timeAgo,
        like: 'N/A', 
        comment: 'N/A',
        _viewsNumeric: viewsNumeric,
        _subscriberNumeric: subscriberNumeric,
        _daysAgo: daysAgo
    });
}

videos.sort((a, b) => {
    if (a._daysAgo !== b._daysAgo) {
        return a._daysAgo - b._daysAgo; 
    }
    if (b._viewsNumeric !== a._viewsNumeric) {
        return b._viewsNumeric - a._viewsNumeric;
    }
    return b._subscriberNumeric - a._subscriberNumeric;
});

const topNVideos = videos.slice(0, limit);

const finalVideos = topNVideos.map(video => {
    delete video._viewsNumeric;
    delete video._subscriberNumeric;
    delete video._daysAgo;
    return video;
});

return [{ json: { videos: finalVideos } }];

const output = {};
const inputItem = $input.first().json;

if (!inputItem || !inputItem.data || !inputItem.data.markdown) {
    return [{ json: { error: "Markdown data not found in input." } }];
}

const markdown = inputItem.data.markdown;



let channelNameMatch = markdown.match(/\[([^\]]+)\]\(https:\/\/www\.youtube\.com\/@[^\)]+\)/);
if (!channelNameMatch) {
    channelNameMatch = markdown.match(/\[([^\]]+)\]\(https:\/\/www\.youtube\.com\/channel\/[^\)]+\)/);
}
output.channelName = channelNameMatch ? channelNameMatch[1].trim() : 'N/A';


let viewsMatch = markdown.match(/(\d+(?:,\d+)*)\s+views/);
if (!viewsMatch) {
    // Fallback: Try to find views in format like "722K views"
    viewsMatch = markdown.match(/(\d+(?:\.\d+)?[KMB])\s+views/);
}
output.views = viewsMatch ? viewsMatch[1].trim() : 'N/A';


let likesMatch = markdown.match(/(\d+(?:\.\d+)?[KMB]?)\s*(?:Share|Dislike)/);
if (!likesMatch) {
    likesMatch = markdown.match(/^(\d+(?:\.\d+)?[KMB]?)$/m);
}
output.totalLikes = likesMatch ? likesMatch[1].trim() : 'N/A';

let descriptionMatch = markdown.match(/Show less\n\n([\s\S]*?)(?:\n\nTimestamps:|\n\nHow this was made|\n\n\.\.\.more)/i);
if (!descriptionMatch) {

    descriptionMatch = markdown.match(/\d+\s+views[\s\S]*?\n\n([\s\S]*?)(?:\n\nTimestamps:|\n\nHow this was made)/i);
}

let description = 'N/A';
if (descriptionMatch) {
    description = descriptionMatch[1]
        .replace(/\n\n/g, ' ')                      
        .replace(/\n/g, ' ')                        
        .replace(/\[.*?\]\(.*?\)/g, '')           
        .replace(/!\[.*?\]\(.*?\)/g, '')          
        .replace(/\s+/g, ' ')                       
        .replace(/Show lessRead more/g, '')         // Remove UI text
        .replace(/Show less/g, '')
        .replace(/Read more/g, '')
        .replace(/\.\.\.more/g, '')
        .trim();

    // Limit description to first 500 characters for cleaner output
    if (description.length > 500) {
        description = description.substring(0, 500) + '...';
    }
}

output.description = description;


let urlMatch = markdown.match(/https:\/\/www\.youtube\.com\/watch\?v=([a-zA-Z0-9_-]+)/);
if (urlMatch) {
    output.url = `https://www.youtube.com/watch?v=${urlMatch[1]}`;
} else {
    output.url = 'N/A';
}



const comments = [];



const commentRegex = /!\[\]\((https?:\/\/[^\)]+)\)\s*\n\n([^\n]*?)(?:\n\n(?:Show lessRead more|Read more|Show less)?)?\n\nLike\s*\n\n(\d+(?:\.\d+)?[KMB]?)?\s*\n\nDislike/gs;

let commentMatch;
let count = 0;

while ((commentMatch = commentRegex.exec(markdown)) !== null) {
    let commentText = commentMatch[2] || '';
    let likesRaw = commentMatch[3] || '0';

    // Clean up comment text
    commentText = commentText
        .replace(/\\n/g, ' ')                    // Remove backslash escapes
        .replace(/\s+/g, ' ')                    // Normalize whitespace
        .replace(/Show lessRead more/g, '')      // Remove YouTube UI text
        .replace(/Show less/g, '')
        .replace(/Read more/g, '')
        .replace(/\[.*?\]/g, '')                 // Remove markdown links
        .replace(/!\[.*?\]\(.*?\)/g, '')         // Remove markdown images
        .replace(/​@\w+\s*-\s*/g, '')            // Remove mentions like @user -
        .replace(/\s*❤ by @\w+/g, '')           // Remove heart reactions
        .replace(/!\[.*?\]\(.*?\)/g, '')         // Remove emoji images
        .trim();

    // Convert likes from format like "333" or "10K" to number
    let likesNumber = 0;
    if (likesRaw && likesRaw !== '0') {
        if (likesRaw.includes('K')) {
            likesNumber = parseInt(likesRaw) * 1000;
        } else if (likesRaw.includes('M')) {
            likesNumber = parseInt(likesRaw) * 1000000;
        } else {
            likesNumber = parseInt(likesRaw) || 0;
        }
    }

    // Only include comments with meaningful content (at least 5 characters)
    if (commentText.length >= 5) {
        comments.push({
            comment: commentText,
            likes: likesNumber
        });
        count++;
    }
}

// Sort by likes in descending order and take top 20
comments.sort((a, b) => b.likes - a.likes);
output.top20Comments = comments.slice(0, 20);
output.totalCommentsExtracted = count;


return [{ json: output }];
